import { useState } from "react";
import PizzaBase from "./pizza_base.png";

const toppings = ["🍄", "🧀", "🌽", "🍍", "🧅", "🌶️"];
const toppingPrices = {"🍄": 40, "🧀": 45, "🌽": 30, "🍍": 35, "🧅": 20, "🌶️": 25};

export default function PizzaBuilder() {
  const [selected, setSelected] = useState(toppings[0]);
  const [pizza, setPizza] = useState([]);

  function handlePizzaClick(event) {
    const topping = {
      emoji: selected,
      x: event.offsetX,
      y: event.offsetY,
    };

    setPizza([...pizza, topping]);
  }

  function calculateTotal() {
    let total = 299;
    for (const topping of pizza) {
      total += toppingPrices[topping.emoji] || 0;
    }
    return total;
  }

  return (
    <main>
      <h1>🍕 Pizza Builder</h1>

      <h2>
        <strong>Total:</strong> ₹{calculateTotal()}
      </h2>

      <p>
        {toppings.map((topping) => (
          <button
            key={topping}
            onClick={() => setSelected(topping)}
            disabled={selected === topping}
          >
            {topping}
          </button>
        ))}
      </p>

      <figure
        onClick={handlePizzaClick}
        style={{ position: "relative", margin: 0 }}>
        <img src={PizzaBase} height="500" />

        {pizza.map((topping, index) => (
          <p
            key={index}
            style={{
              position: "absolute",
              left: topping.x,
              top: topping.y,
            }}
          >
            {topping.emoji}
          </p>
        ))}
      </figure>
    </main>
  );
}
